args.TargetContent:
"        } else if (tabName === 'Pages') {
          document.getElementById('tabPages').classList.add('active');
          document.getElementById('customizerPagesTab').style.display = 'block';
          // Auto-select first page and show page builder canvas
          loadCustomizerPages().then(() => {
            if (!activeCustomizerPageId) {
              const websiteId = cmsState.activeWebsiteId || (cmsState.websites && cmsState.websites[0]?.id);
              const websitePages = (cmsState.pages || []).filter(p => p.websiteId === websiteId);
              if (websitePages.length > 0) {
                selectCustomizerPage(websitePages[0].id);
              }
            } else {
              // Re-activate the existing selection to ensure iframe is visible
              selectCustomizerPage(activeCustomizerPageId);
            }
          });
        }"
